import { Component } from '@angular/core';
import { MySubjectService } from './my-subject.service';

@Component({ ... })
export class OtherComponent {
  constructor(private mySubjectService: MySubjectService) { }

  subscribeToMySubject() {
    this.mySubjectService.getMySubject().subscribe((value) => console.log(value));
  }
}
```
Another way to expose the subject is to use a `Subject` that is shared between components through a shared service. This allows multiple components to share the same subject and communicate with each other through it.
