class GroupsModel: ObservableObject {
    @Published var groups: [Group] = []

    private let fetchHandler = URLSession_fetch("http://localhost:8000/api(groups)")

    private var isLoading = false

    private func fetchGroups() async {
        isLoading = true
        do {
            let response = await fetchHandler()
            if let json = response as? JSONContent {
                if let data = json["data"] as? [Dictionary<String, String>] {
                    groups = data.compactMap { group in
                        guard let name = group["name"] as? String,
                              let items = group["items"] as? [String] else {
