                        }
                        return Group(name: name, items: items)
                    }
                }
            }
        } catch {
            print("Error fetching groups: \(error)")
        } finally {
            isLoading = false
        }
    }

    var groups: [Group] {
        if isLoading {
            print("Loading groups...")
            return []
        }
        return groups
    }
}

